# ── Configuration via environment variables ──────────────────────────────────
RESULTS_BUCKET = os.environ.get("RESULTS_BUCKET", "image-processor-results")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
MAX_LABELS = int(os.environ.get("MAX_LABELS", "10"))
MIN_CONFIDENCE = float(os.environ.get("MIN_CONFIDENCE", "80.0"))
LOG_LEVEL = os.environ.get("LOG_LEVEL", "INFO")

# ── Logger ───────────────────────────────────────────────────────────────────
logger = logging.getLogger("ImageProcessor")
logger.setLevel(getattr(logging, LOG_LEVEL, logging.INFO))

# ── AWS Clients (reused across warm invocations) ────────────────────────────
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")
rekognition_client = boto3.client("rekognition")


# ── Helper functions ─────────────────────────────────────────────────────────

def _supported_image(key: str) -> bool:
    """Return True if the S3 key looks like an image we can process."""
    return key.lower().endswith((".jpg", ".jpeg", ".png", ".bmp", ".gif"))


def _detect_labels(bucket: str, key: str) -> dict:
    """Call Rekognition DetectLabels on an S3 object."""
    response = rekognition_client.detect_labels(
        Image={"S3Object": {"Bucket": bucket, "Name": key}},
        MaxLabels=MAX_LABELS,
        MinConfidence=MIN_CONFIDENCE,
    )
    return response


def _detect_moderation_labels(bucket: str, key: str) -> dict:
    """Call Rekognition DetectModerationLabels for content moderation."""
    response = rekognition_client.detect_moderation_labels(
        Image={"S3Object": {"Bucket": bucket, "Name": key}},
        MinConfidence=MIN_CONFIDENCE,
    )
    return response


def _build_result(
    bucket: str,
    key: str,
    labels_response: dict,
    moderation_response: dict,
) -> dict:
    """Assemble a tidy result payload."""
    labels = [
        {
            "Name": lbl["Name"],
            "Confidence": round(lbl["Confidence"], 2),
            "Categories": [p["Name"] for p in lbl.get("Parents", [])],
        }
        for lbl in labels_response.get("Labels", [])
    ]

    moderation_labels = [
        {
            "Name": lbl["Name"],
            "Confidence": round(lbl["Confidence"], 2),
            "ParentName": lbl.get("ParentName", ""),
        }
        for lbl in moderation_response.get("ModerationLabels", [])
    ]

    return {
        "image": {"bucket": bucket, "key": key},
        "processedAt": datetime.utcnow().isoformat() + "Z",
        "labels": labels,
        "moderationLabels": moderation_labels,
        "isFlagged": len(moderation_labels) > 0,
        "labelCount": len(labels),
    }


def _write_results_to_s3(result: dict, source_key: str) -> str:
    """Write the JSON result to the results bucket. Returns the result key."""
    result_key = (
        f"results/{datetime.utcnow().strftime('%Y/%m/%d')}/"
        f"{uuid.uuid4().hex}_{os.path.basename(source_key)}.json"
    )
    s3_client.put_object(
        Bucket=RESULTS_BUCKET,
        Key=result_key,
        Body=json.dumps(result, indent=2),
        ContentType="application/json",
    )
    logger.info("Results written to s3://%s/%s", RESULTS_BUCKET, result_key)
    return result_key


def _publish_notification(result: dict, result_key: str) -> None:
    """Publish a summary notification to SNS."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not set – skipping notification.")
        return

    subject = (
        "⚠️ Flagged Image Processed"
        if result["isFlagged"]
        else "✅ Image Processed"
    )

    top_labels = ", ".join(l["Name"] for l in result["labels"][:5])

    message = (
        f"Image: s3://{result['image']['bucket']}/{result['image']['key']}\n"
        f"Processed at: {result['processedAt']}\n"
        f"Labels ({result['labelCount']}): {top_labels}\n"
        f"Flagged: {result['isFlagged']}\n"
        f"Results: s3://{RESULTS_BUCKET}/{result_key}\n"
    )

    sns_client.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=message,
        MessageAttributes={
            "isFlagged": {
                "DataType": "String",
                "StringValue": str(result["isFlagged"]),
            },
            "labelCount": {
                "DataType": "Number",
                "StringValue": str(result["labelCount"]),
            },
        },
    )
    logger.info("SNS notification sent to %s", SNS_TOPIC_ARN)


def _process_record(record: dict) -> dict:
    """Process a single S3 event record."""
    bucket = record["s3"]["bucket"]["name"]
    key = unquote_plus(record["s3"]["object"]["key"])
    size = record["s3"]["object"].get("size", 0)

    logger.info(
        "Processing image – bucket=%s key=%s size=%s",
        bucket,
        key,
        size,
    )

    if not _supported_image(key):
        logger.warning("Unsupported file type, skipping: %s", key)
        return {"status": "skipped", "reason": "unsupported_type", "key": key}

    # 1. Analyse the image with Rekognition
    labels_response = _detect_labels(bucket, key)
    moderation_response = _detect_moderation_labels(bucket, key)

    # 2. Build structured result
    result = _build_result(bucket, key, labels_response, moderation_response)

    # 3. Persist results to S3
    result_key = _write_results_to_s3(result, key)

    # 4. Notify via SNS
    _publish_notification(result, result_key)

    logger.info(
        "Finished processing %s – %d labels, flagged=%s",
        key,
        result["labelCount"],
        result["isFlagged"],
    )

    return {
        "status": "processed",
        "key": key,
        "resultKey": result_key,
        "labelCount": result["labelCount"],
        "isFlagged": result["isFlagged"],
    }


# ── Lambda entry point ──────────────────────────────────────────────────────

def lambda_handler(event, context):
    """
    Triggered by S3 PutObject events.

    Expected event shape (S3 notification):
    {
      "Records": [
        {
          "s3": {
            "bucket": { "name": "uploads-bucket" },
            "object": { "key": "user123/photo.jpg", "size": 123456 }
          }
        }
      ]
    }
    """
    logger.info(
        "Lambda invoked – request_id=%s records=%d",
        context.aws_request_id if context else "local",
        len(event.get("Records", [])),
    )

    results = []
    errors = []

    for idx, record in enumerate(event.get("Records", [])):
        try:
            result = _process_record(record)
            results.append(result)
        except ClientError as exc:
            error_code = exc.response["Error"]["Code"]
            error_msg = exc.response["Error"]["Message"]
            logger.error(
                "AWS error processing record %d: [%s] %s",
                idx,
                error_code,
                error_msg,
                exc_info=True,
            )
            errors.append(
                {
                    "record_index": idx,
                    "error_code": error_code,
                    "error_message": error_msg,
                }
            )
        except Exception as exc:
            logger.error(
                "Unexpected error processing record %d: %s",
                idx,
                str(exc),
                exc_info=True,
            )
            errors.append(
                {
                    "record_index": idx,
                    "error_code": "UNKNOWN",
                    "error_message": str(exc),
                }
            )

    response_body = {
        "processed": len(results),
        "errors": len(errors),
        "results": results,
    }

    if errors:
        response_body["errorDetails"] = errors
        logger.warning(
            "Completed with %d error(s) out of %d record(s).",
            len(errors),
            len(event.get("Records", [])),
        )

    # If *all* records failed, raise so the invocation is marked as an error
    # and the event can be retried / sent to a DLQ.
    if errors and not results:
        raise RuntimeError(
            f"All {len(errors)} record(s) failed. "
            f"First error: {errors[0]['error_message']}"
        )

    return {
        "statusCode": 200,
        "body": json.dumps(response_body, default=str),
    }